import threading
from typing import Dict, List
from dataclasses import dataclass
from enum import Enum
from decimal import Decimal
import time

class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"

@dataclass
class Transaction:
    account_id: str
    transaction_type: TransactionType
    amount: Decimal
    timestamp: float
    target_account_id: str = None

class FinancialProcessor:
    def __init__(self):
        self.accounts: Dict[str, Decimal] = {}
        self.transactions: List[Transaction] = []
        self._lock = threading.RLock()
    
    def process_transaction(self, transaction: Transaction) -> bool:
        with self._lock:
            # Check if account exists for withdrawal/deposit
            if transaction.transaction_type in [TransactionType.WITHDRAWAL, TransactionType.DEPOSIT]:
                if transaction.account_id not in self.accounts:
                    return False
                
                # Check sufficient funds for withdrawal
                if transaction.transaction_type == TransactionType.WITHDRAWAL:
                    if self.accounts[transaction.account_id] < transaction.amount:
                        return False
                
                # Update balance
                if transaction.transaction_type == TransactionType.DEPOSIT:
                    self.accounts[transaction.account_id] += transaction.amount
                else:  # WITHDRAWAL
                    self.accounts[transaction.account_id] -= transaction.amount
                    
            elif transaction.transaction_type == TransactionType.TRANSFER:
                # Check if both accounts exist
                if transaction.account_id not in self.accounts or transaction.target_account_id not in self.accounts:
                    return False
                
                # Check sufficient funds
                if self.accounts[transaction.account_id] < transaction.amount:
                    return False
                
                # Atomic transfer
                self.accounts[transaction.account_id] -= transaction.amount
                self.accounts[transaction.target_account_id] += transaction.amount
            
            # Record transaction
            self.transactions.append(transaction)
            return True
    
    def get_balance(self, account_id: str) -> Decimal:
        with self._lock:
            return self.accounts.get(account_id, Decimal('0.00'))
    
    def get_account_history(self, account_id: str) -> List[Transaction]:
        with self._lock:
            return [t for t in self.transactions if t.account_id == account_id]

# Test function
def test_concurrent_transactions():
    processor = FinancialProcessor()
    processor.accounts['acc1'] = Decimal('1000.00')
    processor.accounts['acc2'] = Decimal('500.00')
    
    def worker():
        for i in range(10):
            # Deposit
            processor.process_transaction(Transaction('acc1', TransactionType.DEPOSIT, Decimal('100.00'), time.time()))
            # Withdrawal
            processor.process_transaction(Transaction('acc1', TransactionType.WITHDRAWAL, Decimal('50.00'), time.time()))
            # Transfer
            processor.process_transaction(Transaction('acc1', TransactionType.TRANSFER, Decimal('25.00'), time.time(), 'acc2'))
    
    threads = []
    for _ in range(5):
        t = threading.Thread(target=worker)
        threads.append(t)
        t.start()
    
    for t in threads:
        t.join()
    
    print(f"Final balance acc1: {processor.get_balance('acc1')}")
    print(f"Final balance acc2: {processor.get_balance('acc2')}")

# Run test
test_concurrent_transactions()